const binaryProperties = items[0].binary;
if (!binaryProperties || Object.keys(binaryProperties).length === 0) {
  throw new Error("Файл не пришёл как binary объект.");
}

const propertyName = Object.keys(binaryProperties)[0];
const binary = binaryProperties[propertyName];

const buffer = await this.helpers.getBinaryDataBuffer(0, propertyName);

return [{
  json: {
    rawDocument: {
      content: buffer.toString('base64'),
      mimeType: binary.mimeType || 'application/pdf'
    }
  }
}];

const raw = $json.value || $json.output;
if (!raw) {
  throw new Error("Поле value или output не найдено");
}

const data = JSON.parse(raw);
const row = {};

// Преобразуем простые поля
for (const key of Object.keys(data)) {
  if (key !== "table_data") {
    row[key] = data[key];
  }
}

// Разворачиваем table_data (если есть)
if (Array.isArray(data.table_data)) {
  data.table_data.forEach((r, idx) => {
    for (const field of Object.keys(r)) {
      row[`table_data[${idx}].${field}`] = r[field];
    }
  });
}

return [{ json: row }];

const it = $input.first();
const j = it.json || {};

let tgUser = null;
let first_name = null;
let last_name = null;
let fileName = null;
let comment = '';

try {
  const bin = it.binary?.data || Object.values(it.binary || {})[0];
  if (bin?.fileName) fileName = bin.fileName;
} catch {}

if (j?.body?.tg_data) {
  comment = j.body.comment ?? '';
  let parsed = {};
  try {
    const params = new URLSearchParams(j.body.tg_data);
    for (const [k, v] of params.entries()) parsed[k] = v;
  } catch {
    const decoded = decodeURIComponent(j.body.tg_data);
    for (const p of decoded.split('&')) {
      const [k, v] = p.split('=');
      parsed[k] = v;
    }
  }
  let user = {};
  try { user = JSON.parse(decodeURIComponent(parsed.user || '{}')); }
  catch { try { user = JSON.parse(parsed.user || '{}'); } catch { user = {}; } }
  tgUser = user.id ?? null;
  first_name = user.first_name ?? null;
  last_name = user.last_name ?? null;
} else if (j?.tgUser) {
  comment = j.comment ?? '';
  tgUser = j.tgUser ?? null;
  first_name = j.first_name ?? null;
  last_name = j.last_name ?? null;
  if (j.fileName) fileName = j.fileName;
} else {
  comment = j.comment ?? '';
  tgUser = j.userId ?? null;
  first_name = j.first_name ?? null;
  last_name = j.last_name ?? null;
}

const displayName = [first_name, last_name].filter(Boolean).join(' ') || (tgUser != null ? String(tgUser) : '');

return [{ json: { tgUser, first_name, last_name, fileName, displayName, comment } }];

const merged = {};
for (const item of $input.all()) Object.assign(merged, item.json);

const bin = (merged['9. customer_bin'] ?? '').toString().trim();
let val = '';
if (bin === '190540030056') val = 'ET';
else if (bin === '220340004642') val = 'ETT';
else if (bin === '240440031042') val = 'B2B';

merged['route_code'] = val;
return [{ json: merged }];

const BYPASS_DECODER = false;

const idx = items.findIndex(i => i?.binary && Object.keys(i.binary).length > 0);
if (idx === -1) return [];

const item = items[idx];
const binProps = Object.keys(item.binary);
const srcProp = binProps.includes('data') ? 'data' : binProps[0];
const binMeta = item.binary[srcProp];
const msg = item.json?.message;
if (!msg?.document) return [];

const tgUser = msg.from?.id;
const first_name = msg.from?.first_name ?? null;
const last_name = msg.from?.last_name ?? null;
const username = msg.from?.username ?? null;
const fileName = msg.document.file_name ?? binMeta?.fileName ?? null;
const mimeType = msg.document.mime_type ?? binMeta?.mimeType ?? 'application/octet-stream';

if (!BYPASS_DECODER) {
  item.json = { tgUser, first_name, last_name, username, fileName, mimeType, source: 'telegram' };
  if (srcProp !== 'data') {
    item.binary.data = binMeta;
    delete item.binary[srcProp];
  }
  return [item];
} else {
  const buf = await this.helpers.getBinaryDataBuffer(idx, srcProp);
  return [{
    json: {
      rawDocument: { content: buf.toString('base64'), mimeType, fileName },
      tgUser, first_name, last_name, username, source: 'telegram'
    }
  }];
}

const crypto = require('crypto');
const input = $input.first();
const tgData = input.json.body?.tg_data || '';
const botToken = process.env.TELEGRAM_BOT_TOKEN || '';

const params = new URLSearchParams(tgData);
const hash = params.get('hash');
params.delete('hash');

const dataCheckString = Array.from(params.entries())
  .sort(([a], [b]) => a.localeCompare(b))
  .map(([k, v]) => `${k}=${v}`)
  .join('\n');

const secretKey = crypto.createHmac('sha256', 'WebAppData').update(botToken).digest();
const computedHash = crypto.createHmac('sha256', secretKey).update(dataCheckString).digest('hex');

const isValid = computedHash === hash;
let tgUser = {};
try {
  tgUser = JSON.parse(decodeURIComponent(params.get('user') || '{}'));
} catch(e) {}

return [{ json: { ...input.json, isValid, tgUser }, binary: input.binary }];
